example_bad:
fn main() {
    let s = String::from("hello");
    let s2 = s;
    println!("{}", s); // Error: value used after move
}

fixes.code:
let s = String::from("hello");
let s2 = s.clone();
println!("{}", s); // Works!

let s = String::from("hello");
let s2 = &s;
println!("{}", s); // Works!
